import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { HackathonService } from '../../../../core/services/hackathon.service';
import { TeamService } from '../../../../core/services/team.service';
import { HackathonSummaryDTO, StatoHackathon } from '../../../../core/models/hackathon.model';

@Component({
  selector: 'app-hackathons',
  templateUrl: './hackathons.component.html',
  styleUrls: ['./hackathons.component.scss']
})
export class HackathonsComponent implements OnInit {
  activeFilter = 'all';
  hackathons: HackathonSummaryDTO[] = [];
  myHackathonIds: Set<string> = new Set();
  isLoading = true;
  errorMessage = '';

  constructor(
    private hackathonService: HackathonService,
    private teamService: TeamService,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.loadHackathons();
  }

  loadHackathons(): void {
    this.isLoading = true;
    this.errorMessage = '';

    this.hackathonService.getHackathons().subscribe({
      next: (hackathons) => {
        this.hackathons = hackathons;
        this.isLoading = false;
      },
      error: (error) => {
        this.errorMessage = 'Failed to load hackathons. Please try again.';
        this.isLoading = false;
      }
    });

    // Load user's registered hackathons (silently — no hard error if user has no team)
    this.hackathonService.getMyHackathons().subscribe({
      next: (myHackathons) => {
        this.myHackathonIds = new Set(myHackathons.map(h => h.id));
      },
      error: () => {
        // If user has no token or no team, just leave the set empty
        this.myHackathonIds = new Set();
      }
    });
  }

  get filteredHackathons(): HackathonSummaryDTO[] {
    if (this.activeFilter === 'all') {
      return this.hackathons;
    }
    return this.hackathons.filter(hackathon => hackathon.stato === this.activeFilter);
  }

  setFilter(filter: string): void {
    this.activeFilter = filter;
  }

  getStatusDisplay(stato: string): string {
    switch (stato) {
      case 'IN_ISCRIZIONE':
        return 'Open for Registration';
      case 'IN_CORSO':
        return 'In Progress';
      case 'CONCLUSO':
        return 'Completed';
      default:
        return stato;
    }
  }

  navigateTo(route: string): void {
    this.router.navigate([route]);
  }

  viewDetails(hackathon: HackathonSummaryDTO): void {
    this.router.navigate(['/hackathons', hackathon.id]);
  }

  isRegistered(hackathon: HackathonSummaryDTO): boolean {
    return this.myHackathonIds.has(hackathon.id);
  }

  joinHackathon(hackathon: HackathonSummaryDTO): void {
    this.teamService.getMyTeams().subscribe({
      next: (teams) => {
        if (!teams || teams.length === 0) {
          this.errorMessage = 'Devi essere in un team per iscriverti a un hackathon.';
          return;
        }
        const teamId = teams[0].id;
        this.hackathonService.joinHackathon(hackathon.id, teamId).subscribe({
          next: (response) => {
            console.log('Team successfully registered:', response);
            alert(`Team iscritto con successo a ${hackathon.nome}!`);
          },
          error: (error) => {
            this.errorMessage = error.error?.message || 'Errore durante l\'iscrizione. Riprova.';
          }
        });
      },
      error: () => {
        this.errorMessage = 'Impossibile recuperare le informazioni del team. Riprova.';
      }
    });
  }
}
<div class="hackathons-container">
  <!-- Welcome Section -->
  <div class="welcome-section">
    <div class="welcome-content">
      <h1 class="welcome-title">Hackathons 🏆</h1>
      <p class="welcome-subtitle">Discover exciting competitions and challenges</p>
    </div>
    <div class="welcome-actions">
      <button class="btn-primary" *appHasRole="['ORGANIZZATORE']" (click)="navigateTo('/hackathons/create')">
        <span>➕</span>
        <span>Create Hackathon</span>
      </button>
    </div>
  </div>

  <!-- Filter Tabs -->
  <div class="filter-section">
    <div class="filter-tabs">
      <button class="filter-tab" [class.active]="activeFilter === 'all'" (click)="setFilter('all')">
        <span>🎯</span>
        <span>All Hackathons</span>
      </button>
      <button class="filter-tab" [class.active]="activeFilter === 'IN_ISCRIZIONE'" (click)="setFilter('IN_ISCRIZIONE')">
        <span>🔓</span>
        <span>Open for Registration</span>
      </button>
      <button class="filter-tab" [class.active]="activeFilter === 'IN_CORSO'" (click)="setFilter('IN_CORSO')">
        <span>🚀</span>
        <span>In Progress</span>
      </button>
      <button class="filter-tab" [class.active]="activeFilter === 'CONCLUSO'" (click)="setFilter('CONCLUSO')">
        <span>🏁</span>
        <span>Completed</span>
      </button>
    </div>
  </div>

  <!-- Main Content -->
  <div class="hackathons-content">
    <!-- Loading State -->
    <div class="loading-state" *ngIf="isLoading">
      <div class="loading-spinner">
        <div class="spinner"></div>
        <p>Loading amazing hackathons...</p>
      </div>
    </div>

    <!-- Error State -->
    <div class="error-state" *ngIf="errorMessage">
      <div class="error-card">
        <div class="error-icon">⚠️</div>
        <h3>Oops! Something went wrong</h3>
        <p>{{ errorMessage }}</p>
        <button class="btn-secondary" (click)="loadHackathons()">Try Again</button>
      </div>
    </div>

    <!-- Hackathons Grid -->
    <div class="hackathons-grid" *ngIf="!isLoading && !errorMessage">
      <div class="hackathon-card" 
           [class.status-open]="hackathon.stato === 'IN_ISCRIZIONE'"
           [class.status-in-progress]="hackathon.stato === 'IN_CORSO'"
           [class.status-closed]="hackathon.stato === 'CONCLUSO'"
           *ngFor="let hackathon of filteredHackathons">

        <!-- Card Header -->
        <div class="card-header">
          <div class="status-badge" 
               [class.badge-open]="hackathon.stato === 'IN_ISCRIZIONE'"
               [class.badge-in-progress]="hackathon.stato === 'IN_CORSO'"
               [class.badge-closed]="hackathon.stato === 'CONCLUSO'">
            {{ getStatusDisplay(hackathon.stato) }}
          </div>
          <div class="prize-amount" *ngIf="hackathon.premioInDenaro">
            <span>💰</span>
            <span>${{ hackathon.premioInDenaro }}</span>
          </div>
        </div>

        <!-- Card Content -->
        <div class="card-content">
          <h3 class="hackathon-title">{{ hackathon.nome }}</h3>
          <p class="hackathon-description">{{ hackathon.regolamento }}</p>

          <div class="hackathon-meta">
            <div class="meta-item">
              <span class="meta-icon">📅</span>
              <div class="meta-content">
                <span class="meta-label">Start Date</span>
                <span class="meta-value">{{ hackathon.dataInizio | date:'mediumDate' }}</span>
              </div>
            </div>
            <div class="meta-item">
              <span class="meta-icon">📍</span>
              <div class="meta-content">
                <span class="meta-label">Location</span>
                <span class="meta-value">{{ hackathon.luogo || 'Online' }}</span>
              </div>
            </div>
            <div class="meta-item">
              <span class="meta-icon">�</span>
              <div class="meta-content">
                <span class="meta-label">Organizer</span>
                <span class="meta-value">{{ hackathon.organizzatoreNome || 'HackHub' }}</span>
              </div>
            </div>
          </div>
        </div>

        <!-- Card Actions -->
        <div class="card-actions">
          <button class="btn-outline" (click)="viewDetails(hackathon)">
            <span>👁️</span>
            <span>View Details</span>
          </button>
          <ng-container *ngIf="hackathon.stato === 'IN_ISCRIZIONE'">
            <button class="btn-primary" 
                    *appHasRole="['UTENTE_SENZA_TEAM', 'MEMBRO_TEAM', 'LEADER_TEAM']"
                    (click)="joinHackathon(hackathon)">
              <span>🚀</span>
              <span>Join Hackathon</span>
            </button>
          </ng-container>
        </div>
      </div>

      <!-- Empty State -->
      <div class="empty-state" *ngIf="filteredHackathons.length === 0">
        <div class="empty-card">
          <div class="empty-icon">🏆</div>
          <h3>No hackathons found</h3>
          <p>Try adjusting your filters or check back later for new competitions.</p>
          <button class="btn-primary" *appHasRole="['ORGANIZZATORE']" (click)="navigateTo('/hackathons/create')">
            <span>➕</span>
            <span>Create Hackathon</span>
          </button>
        </div>
      </div>
    </div>
  </div>
</div>
